import React, { useState } from 'react';
import { FaCalendarAlt, FaClock, FaTimes } from 'react-icons/fa';
import './MyAppointments.css';

const sampleAppointments = [
  {
    id: 'APT12345',
    doctor: 'Dr. Rajesh Kumar',
    specialty: 'General Medicine',
    date: 'Mon, Sep 15, 2025',
    time: '10:00',
    bookedOn: 'Sat, Sep 13, 2025',
    notes: 'Regular checkup',
    status: 'Scheduled'
  },
  {
    id: 'APT67890',
    doctor: 'Dr. Priya Sharma',
    specialty: 'Cardiology',
    date: 'Thu, Sep 18, 2025',
    time: '14:30',
    bookedOn: 'Mon, Sep 15, 2025',
    notes: 'Follow-up',
    status: 'Scheduled'
  }
];

export default function MyAppointments() {
  const [tab, setTab] = useState('upcoming');

  const renderCard = (a) => (
    <div className="ma-card" key={a.id}>
      <div className="ma-left">
        <div className="ma-avatar">{a.doctor.split(' ').map(n=>n[0]).slice(0,2).join('')}</div>
      </div>
      <div className="ma-body">
        <h4 className="ma-doctor">{a.doctor}</h4>
        <p className="ma-specialty">{a.specialty}</p>
        <div className="ma-meta">
          <div><small className="text-muted">Date:</small><div className="ma-strong">{a.date}</div></div>
          <div><small className="text-muted">Time:</small><div className="ma-strong">{a.time}</div></div>
          <div><small className="text-muted">Booked:</small><div className="ma-strong">{a.bookedOn}</div></div>
        </div>
        <div className="ma-notes"><strong>Notes:</strong><div>{a.notes}</div></div>
        <div className="ma-actions">
          <button className="btn btn-outline">Reschedule</button>
          <button className="btn btn-outline-danger">Cancel</button>
        </div>
      </div>
      <div className="ma-right">
        <div className="ma-status">{a.status}</div>
      </div>
    </div>
  );

  return (
    <div className="ma-page container mx-auto px-6 py-8">
      <h1 className="text-2xl font-bold mb-4">My Appointments</h1>

      <div className="ma-tabs card mb-6">
        <button className={`ma-tab ${tab==='upcoming'?'active':''}`} onClick={()=>setTab('upcoming')}>Upcoming</button>
        <button className={`ma-tab ${tab==='past'?'active':''}`} onClick={()=>setTab('past')}>Past</button>
        <button className={`ma-tab ${tab==='cancelled'?'active':''}`} onClick={()=>setTab('cancelled')}>Cancelled</button>
      </div>

      <div className="ma-list">
        {tab === 'upcoming' && sampleAppointments.map(renderCard)}
        {tab === 'past' && <div className="text-muted">No past appointments</div>}
        {tab === 'cancelled' && <div className="text-muted">No cancelled appointments</div>}
      </div>
    </div>
  );
}
